import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e as p}from"./app-76561525.js";const t={},e=p(`<p>函数调用函数自身，这种方式称为递归，这种函数称为递归函数</p><p>递归函数使用过程中，需要找到<code>不变的规律</code>和停止递归的<code>边界条件</code>，因为函数自身调用自身，函数本身的结构不变，只是<code>每次传的参数改变</code>啦</p><blockquote><p>递归实现过程(<strong>扩展</strong>)：利用栈的思想，先找边界条件，同时将后面的任务存起来，一直到最前面的边界条件，然后回去，每次从栈中取任务，进行计算，一直到最后一个任务取完，结果也计算完毕</p></blockquote><h2 id="递归过程" tabindex="-1"><a class="header-anchor" href="#递归过程" aria-hidden="true">#</a> 递归过程:</h2><ul><li>递归前进段</li><li>递归边界条件</li><li>递归返回段</li></ul><h2 id="案例讲解" tabindex="-1"><a class="header-anchor" href="#案例讲解" aria-hidden="true">#</a> 案例讲解</h2><h3 id="整数转换为字符串" tabindex="-1"><a class="header-anchor" href="#整数转换为字符串" aria-hidden="true">#</a> 整数转换为字符串</h3><p>将一个整数转换为字符串，如 345转换为&quot;345&quot;</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">trans</span><span class="token punctuation">(</span>num<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">if</span> num <span class="token operator">//</span> <span class="token number">10</span> <span class="token operator">==</span> <span class="token number">0</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token string">&#39;%s&#39;</span><span class="token operator">%</span>num
    <span class="token keyword">else</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> trans<span class="token punctuation">(</span>num<span class="token operator">//</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token operator">+</span><span class="token string">&#39;%s&#39;</span><span class="token operator">%</span><span class="token punctuation">(</span>num<span class="token operator">%</span><span class="token number">10</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="树的高度" tabindex="-1"><a class="header-anchor" href="#树的高度" aria-hidden="true">#</a> 树的高度</h3><p>递归求二叉树深度</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">getHeight</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span>root<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">if</span> root <span class="token keyword">is</span> <span class="token boolean">None</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token number">0</span>
    <span class="token keyword">else</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token builtin">max</span><span class="token punctuation">(</span>self<span class="token punctuation">.</span>getHeight<span class="token punctuation">(</span>root<span class="token punctuation">.</span>left<span class="token punctuation">)</span><span class="token punctuation">,</span> self<span class="token punctuation">.</span>getHeight<span class="token punctuation">(</span>root<span class="token punctuation">.</span>right<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token number">1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="递归实现吸烟问题" tabindex="-1"><a class="header-anchor" href="#递归实现吸烟问题" aria-hidden="true">#</a> 递归实现吸烟问题</h3><p>吸烟有危害，不仅仅危害人体健康，还会对社会产生不良的影响。吸烟还很容易引起喉头炎、气管炎，肺气肿等问题； 那么现在假设人一生抽烟10000根达到极限峰值，再抽一根烟就像压倒骆驼的最后一根稻草，会使人体爆发疾病问题； 每天一个人抽烟的个数都比前天多一根（第一天抽一根），且一周只有工作日（周一~周五）会吸烟； 请使用递归的方式求出一个人按照以上方式抽烟达到10000根，爆发疾病需要历经多少天</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">smoker</span><span class="token punctuation">(</span>day<span class="token punctuation">,</span> count<span class="token punctuation">,</span> amount<span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token triple-quoted-string string">&quot;&quot;&quot;
    递归解决吸烟问题
    :param day: 当前的天数
    :param count: 当天的吸烟数量
    :param amount: 总计的吸烟数量
    :return: 吸到10000根烟的天数
    &quot;&quot;&quot;</span>
    <span class="token keyword">if</span> amount <span class="token operator">&gt;=</span> <span class="token number">10000</span><span class="token punctuation">:</span>
        <span class="token comment"># 如果吸烟总数大于10000， 返回天数</span>
        <span class="token keyword">return</span> day

    <span class="token keyword">else</span><span class="token punctuation">:</span>
        day <span class="token operator">+=</span> <span class="token number">1</span> <span class="token comment"># 每吸一次烟，天数加1</span>
        <span class="token keyword">if</span> day <span class="token operator">%</span> <span class="token number">7</span> <span class="token operator">!=</span> <span class="token number">6</span> <span class="token keyword">and</span> day <span class="token operator">%</span> <span class="token number">7</span> <span class="token operator">!=</span> <span class="token number">0</span><span class="token punctuation">:</span>
            <span class="token comment"># 只有周六，周日不吸烟，判断不是周六，也不是周日</span>
            count <span class="token operator">+=</span> <span class="token number">1</span> <span class="token comment"># 当天吸烟的数量</span>
            amount <span class="token operator">+=</span> count <span class="token comment"># 目前为止，吸烟的总数量</span>

        <span class="token keyword">return</span> smoker<span class="token punctuation">(</span>day<span class="token punctuation">,</span> count<span class="token punctuation">,</span> amount<span class="token punctuation">)</span>


<span class="token keyword">print</span><span class="token punctuation">(</span>smoker<span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment"># 第1天，吸了1根烟，总共吸了1根烟</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="青蛙跳台阶问题" tabindex="-1"><a class="header-anchor" href="#青蛙跳台阶问题" aria-hidden="true">#</a> 青蛙跳台阶问题</h3><p>一只青蛙一次可以跳上1级台阶，也可以跳上2级台阶。求该青蛙跳上一个 <code>n</code> 级的台阶总共有多少种跳法。</p><p>答案需要取模 1e9+7（1000000007），如计算初始结果为：1000000008，请返回 1。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 这个问题，本质是一个斐波那契数列数列求第n项值的问题，如果用递归求，将会超出时间限制</span>
<span class="token comment"># 因此，直接用循环求即可</span>
<span class="token keyword">class</span> <span class="token class-name">Solution</span><span class="token punctuation">:</span>
    <span class="token keyword">def</span> <span class="token function">numWays</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> n<span class="token punctuation">:</span> <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token builtin">int</span><span class="token punctuation">:</span>
        a <span class="token operator">=</span> <span class="token number">1</span>
        b <span class="token operator">=</span> <span class="token number">1</span>
        <span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token builtin">range</span><span class="token punctuation">(</span>n<span class="token punctuation">)</span><span class="token punctuation">:</span>
            a<span class="token punctuation">,</span> b <span class="token operator">=</span> b<span class="token punctuation">,</span> a<span class="token operator">+</span>b
        <span class="token keyword">return</span> a <span class="token operator">%</span> <span class="token number">1000000007</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="汉诺塔问题" tabindex="-1"><a class="header-anchor" href="#汉诺塔问题" aria-hidden="true">#</a> 汉诺塔问题</h3><p>在经典汉诺塔问题中，有 3 根柱子及 N 个不同大小的穿孔圆盘，盘子可以滑入任意一根柱子。一开始，所有盘子自上而下按升序依次套在第一根柱子上(即每一个盘子只能放在更大的盘子上面)。移动圆盘时受到以下限制:<br> (1) 每次只能移动一个盘子;<br> (2) 盘子只能从柱子顶端滑出移到下一根柱子;<br> (3) 盘子只能叠在比它大的盘子上。</p><p>请编写程序，用栈将所有盘子从第一根柱子移到最后一根柱子。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Solution</span><span class="token punctuation">:</span>
    <span class="token keyword">def</span> <span class="token function">hanota</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> A<span class="token punctuation">:</span> List<span class="token punctuation">[</span><span class="token builtin">int</span><span class="token punctuation">]</span><span class="token punctuation">,</span> B<span class="token punctuation">:</span> List<span class="token punctuation">[</span><span class="token builtin">int</span><span class="token punctuation">]</span><span class="token punctuation">,</span> C<span class="token punctuation">:</span> List<span class="token punctuation">[</span><span class="token builtin">int</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span>
        n <span class="token operator">=</span> <span class="token builtin">len</span><span class="token punctuation">(</span>A<span class="token punctuation">)</span>
        self<span class="token punctuation">.</span>move<span class="token punctuation">(</span>n<span class="token punctuation">,</span> A<span class="token punctuation">,</span> B<span class="token punctuation">,</span> C<span class="token punctuation">)</span>
    <span class="token comment"># 定义move 函数移动汉诺塔</span>
    <span class="token keyword">def</span> <span class="token function">move</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span>n<span class="token punctuation">,</span> A<span class="token punctuation">,</span> B<span class="token punctuation">,</span> C<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">if</span> n <span class="token operator">==</span> <span class="token number">1</span><span class="token punctuation">:</span>
            C<span class="token punctuation">.</span>append<span class="token punctuation">(</span>A<span class="token punctuation">[</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
            A<span class="token punctuation">.</span>pop<span class="token punctuation">(</span><span class="token punctuation">)</span>
            <span class="token keyword">return</span> 
        <span class="token keyword">else</span><span class="token punctuation">:</span>
            self<span class="token punctuation">.</span>move<span class="token punctuation">(</span>n<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">,</span> A<span class="token punctuation">,</span> C<span class="token punctuation">,</span> B<span class="token punctuation">)</span>  <span class="token comment"># 将A上面n-1个通过C移到B</span>
            C<span class="token punctuation">.</span>append<span class="token punctuation">(</span>A<span class="token punctuation">[</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span>          <span class="token comment"># 将A最后一个移到C</span>
            A<span class="token punctuation">.</span>pop<span class="token punctuation">(</span><span class="token punctuation">)</span>                  <span class="token comment"># 这时，A空了</span>
            self<span class="token punctuation">.</span>move<span class="token punctuation">(</span>n<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">,</span>B<span class="token punctuation">,</span> A<span class="token punctuation">,</span> C<span class="token punctuation">)</span>   <span class="token comment"># 将B上面n-1个通过空的A移到C</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,23),o=[e];function c(l,i){return s(),a("div",null,o)}const k=n(t,[["render",c],["__file","python递归函数.html.vue"]]);export{k as default};
